import React from "react";

const footerNav = [
  {
    img: "https://img.icons8.com/material-sharp/24/000000/mail.png",
    link: "https://mail.google.com/mail/u/0/#inbox",
  },
  {
    img: "https://img.icons8.com/ios-glyphs/30/000000/phone-disconnected.png",
    link: "tel:+919424391769",
  },
  {
    img: "https://img.icons8.com/material-outlined/24/000000/github.png",
    link: "https://github.com/vilay1702",
  },
  {
    img: "https://img.icons8.com/ios-glyphs/30/000000/twitter--v1.png",
    link: "https://twitter.com/bendevilay",
  },
  {
    img: "https://img.icons8.com/ios-glyphs/30/000000/linkedin.png",
    link: "https://www.linkedin.com/in/vilaybende/",
  },
];

const Footer = () => {
  return (
    <footer className="h-16 sticky bottom-0 bg-white flex items-center justify-between">
      <div className=" flex-1 h-px bg-gray-500 "></div>
      <div className="flex items-center pl-4">
        {footerNav.map(({ img, link }, index) => {
          return (
            <a
              key={index}
              className="h-8 w-8 rounded-full flex justify-center items-center text-gray-900 text  hover:bg-indigo-300 mx-1"
              href={link}
            >
              <img src={img} className="h-6 w-6 " alt="o" />
            </a>
          );
        })}
      </div>
    </footer>
  );
};

export default Footer;
